      "indicators": [
        "'How do I get started'",
        "'What's the next step'",
        "'Can you send me a proposal'",
        "Asking about onboarding",
        "Discussing timeline"
      ],
      "trigger_action": "transition_to_closing"
    },
    "objection": {
      "indicators": [
        "'too expensive'",
        "'not sure if'",
        "'competitor does'",
        "'need to think about'",
        "'check with my team'"
      ],
      "trigger_action": "handle_objection"
    },
    "frustration": {
      "indicators": [
        "Short responses after long ones",
        "'I already told you'",
        "Repeated questions",
        "Negative sentiment score < 0.3",
        "'Just answer my question'"
      ],
      "trigger_action": "de_escalate_or_handoff"
    },
    "disengagement": {
      "indicators": [
        "Single word responses",
        "Increasing response time",
        "'ok' or 'sure' only",
        "No questions for 3+ turns"
      ],
      "trigger_action": "re_engage_or_graceful_exit"
    }
  }
}
```

---

DYNAMIC ROUTING LOGIC:

```json
{
  "turn_analysis_prompt": {
    "instruction": "Analyze user's response and determine next action",
    "input": {
      "latest_message": "{{user_message}}",
      "conversation_state": "{{state}}",
      "previous_ai_message": "{{last_ai_response}}"
